  ('contactPageInfo', $json${"address":"PRINCIPAL, G.Pulla Reddy Engineering College (Autonomous)\nG.Pulla Reddy Nagar, Nandyal Road, Kurnool - 518 007, AP, India.","phone":"08518-270957 (O) / 08518-271017 (O)","fax":"08518-270957","email1":"principal@gprec.ac.in","email2":"principalgprec@gmail.com","howToReach":"On NH-7 (Hyderabad-Bangalore Highway); ~3 hrs from Hyderabad, ~5 hrs from Bangalore, ~10 hrs from Chennai. About 8-10 km from Kurnool bus stand / railway station, on Nandyal Road.","departments":[{"office":"Education & Certificate Verification","email":"info@gprec.ac.in","phone":"08518-270957"},{"office":"Admissions","email":"admissions@gprec.ac.in","phone":"9493458458 (Dr. V. Raghavendra Prasad)"},{"office":"Exam Section","email":"coe@gprec.ac.in","phone":"9705262830 (Sri A. Thammi Reddy)"},{"office":"Placement Cell","email":"tpo@gprec.ac.in","phone":"08518-271054 (Office)"}]}$json$::jsonb),
  ('departmentsList', $json$[{"id":1,"code":"CIV","name":"Civil Engineering (CIV)","about":"The Civil Engineering Department was established in 1984-85 as one of the college's three original departments, with an initial intake of 60 students per batch, now increased to 120. The department has regularly revised its curriculum to incorporate modern topics including AutoCAD, STAAD, Remote Sensing, and GIS.","vision":"To make the Civil Engineering Department at G. Pulla Reddy Engineering College (Autonomous), Kurnool, a leader in the education of practice-oriented Civil Engineers that benefit industry and society.","mission":["Prepare students for Civil Engineering careers through technical knowledge and effective teaching-learning processes.","Produce quality engineers capable of meeting professional demands by focusing on the latest practices.","Inculcate leadership, research capabilities, ethical values, and work culture for societal betterment."],"peos":["Apply a broad, fundamental-based knowledge, and technical skills required for achieving professional success.","Conduct design work in Civil Engineering using software tools while considering economic and environmental factors.","Follow the professional ethics in the practice of the profession showing concern for social responsibilities.","Pursue a professional career aimed at effective management of resources and focus on lifelong learning and research."],"pos":["Engineering knowledge application","Problem analysis","Design/development of solutions","Investigations of complex problems","Modern tool usage","Engineer and society responsibilities","Environment and sustainability","Ethics","Individual and team work","Communication","Project management and finance","Life-long learning"],"psos":["Plan, analyze and design the components of Engineering structures and transportation systems and estimate the cost of construction.","Design and execute the construction of water resources projects and water distribution systems, using Engineering investigations and surveys.","Implement established procedures for laboratory and field investigations on soils and materials ensuring quality execution.","Demonstrate professional ethics and implement the project management principles including project finance, leading to execution of projects."],"programs":[{"name":"B.Tech (Civil Engineering)","intake":"120"},{"name":"M.Tech (Structural Engineering)","intake":"12"},{"name":"Full-time Ph.D","intake":"-"}],"boardOfStudies":[{"position":"Chairman / HOD (Internal)","name":"Dr. K. Chinnapa Reddy","affiliation":"GPREC"},{"position":"Internal","name":"Dr. B.J.S. Vara Prasad","affiliation":"GPREC"},{"position":"Internal","name":"Dr. K.V.S. Gopala Krishna Sastry","affiliation":"GPREC"},{"position":"Internal","name":"Dr. T. Chandrasekhara Reddy","affiliation":"GPREC"},{"position":"Internal","name":"Dr. E. Sanjeeva Rayudu","affiliation":"GPREC"},{"position":"Internal","name":"Dr. T. Sowjanya","affiliation":"GPREC"},{"position":"External (JNTUA)","name":"Dr. M. Srimurali","affiliation":"S.V. University"},{"position":"External (Academic)","name":"Dr. G.L. Siva Kumar Babu","affiliation":"IISc Bangalore (Retired)"},{"position":"External (Academic)","name":"Dr. D. Ravi Prasad","affiliation":"NIT Warangal"},{"position":"Industry","name":"Dr. Gurunath Guduru","affiliation":"Sekura India Management Limited"},{"position":"Alumnus","name":"Sri. Varun Paerakam","affiliation":"CGI Information Systems"}],"studentActivities":["Seminars and activities under the IEI students' chapter.","Technical visits to engineering projects and construction sites.","Participation in technical symposiums and paper/poster presentations.","Guest lectures and demonstrations from academicians and field experts.","Skill development programs for communication abilities.","Industry expert interactions through meetings and presentations.","Participation in cultural, service, and literary forum events.","Physical fitness activities and sports competitions.","Student internships for practical civil engineering exposure."],"facilities":["Material Testing Laboratory","Concrete Technology Laboratory","Geotechnical Engineering Laboratory","Transportation Engineering Laboratory","Fluid Mechanics and Hydraulic Machinery Laboratory","Surveying Laboratory","Engineering Geology Laboratory","Environmental Engineering Laboratory","Civil Computer Laboratory","Structural Engineering Laboratory","Project Work Lab","Research Lab"],"library":[{"item":"Text / Reference Books","quantity":"402"},{"item":"IS Codes & IRC Codes","quantity":"633"},{"item":"Project Work Reports","quantity":"221"},{"item":"Mini Project Work Reports","quantity":"16"},{"item":"CBTs","quantity":"6"}],"departmentAchievements":[{"event":"Study Tour - ATAL Tunnel under AICTE YUVAK Scheme","dates":"17-21 Nov 2021"},{"event":"International Conference on Generic/Pedagogical Research in Civil Engineering","dates":"10-11 Nov 2023"},{"event":"Faculty Development Program on Outcome Based Education","dates":"29 Jul - 2 Aug 2024"},{"event":"Working Model of Major Hydraulic Structures (Ruby Jubilee)","dates":"Feb 2025"},{"event":"Five-Day Workshop on Advanced Technologies in Civil Engineering","dates":"8-12 Dec 2025"}],"studentAchievementsNote":"Multiple students have qualified GATE each year from 2021-22 through 2024-25.","ltScholarship":[{"year":"2018-19","roll":"159X1A0114","name":"C. Raghavendra Reddy","institution":"NIT Trichy"},{"year":"2020-21","roll":"179X1A0176","name":"S. Mustafa Sammer Hasan","institution":"IIT Madras"},{"year":"2022-23","roll":"209X5A01C9","name":"S. Pavan Kumar Reddy","institution":"IIT Madras"},{"year":"2023-24","roll":"209X1A0117","name":"A. Siva Charan Reddy","institution":"IIT Madras"}],"gallery":[{"url":"https://www.gprec.ac.in/wp-content/uploads/2019/07/1b.jpg","caption":"Department activity"},{"url":"https://www.gprec.ac.in/wp-content/uploads/2019/07/2b.jpg","caption":"Department activity"},{"url":"https://www.gprec.ac.in/wp-content/uploads/2019/07/3b.jpg","caption":"Department activity"},{"url":"https://www.gprec.ac.in/wp-content/uploads/2019/07/4b.jpg","caption":"Department activity"},{"url":"https://www.gprec.ac.in/wp-content/uploads/2019/07/5b.jpg","caption":"Department activity"},{"url":"https://www.gprec.ac.in/wp-content/uploads/2019/07/6b.jpg","caption":"Department activity"},{"url":"https://www.gprec.ac.in/wp-content/uploads/2019/07/7b.jpg","caption":"Department activity"},{"url":"https://www.gprec.ac.in/wp-content/uploads/2019/07/8b.jpg","caption":"Department activity"},{"url":"https://www.gprec.ac.in/wp-content/uploads/2026/03/Civil-Srisialam-Trip.jpg","caption":"Civil Srisailam Trip"},{"url":"https://www.gprec.ac.in/wp-content/uploads/2026/03/DGPS-Workshop.jpg","caption":"DGPS Workshop"},{"url":"https://www.gprec.ac.in/wp-content/uploads/2026/03/International-Conference.jpg","caption":"International Conference"},{"url":"https://www.gprec.ac.in/wp-content/uploads/2026/03/5-Days-FDP-OBE.jpg","caption":"5-Day FDP on OBE"},{"url":"https://www.gprec.ac.in/wp-content/uploads/2026/03/Technical-Tour-TungaBadraDam.jpg","caption":"Technical Tour - Tungabhadra Dam"},{"url":"https://www.gprec.ac.in/wp-content/uploads/2026/03/Industrial-Visit-Indraprastha-Housing-Project.jpg","caption":"Industrial Visit - Indraprastha Housing Project"},{"url":"https://www.gprec.ac.in/wp-content/uploads/2026/03/5-Days-Workshop-Advanced-CivilTechnologies.jpg","caption":"5-Day Workshop on Advanced Civil Technologies"}]},{"id":2,"code":"EEE","name":"Electrical and Electronics Engineering (EEE)","about":"Established in 1994 with an initial intake of 60 students (since expanded to 120), the department offers B.Tech, an M.Tech in Automation and Robotics (12 intake), and full-time Ph.D. programmes, supported by 29 faculty members including 17 Ph.D. holders. It operates 13 specialized laboratories including Power Electronics, Drives Control, LabVIEW Academy, and Robotics facilities. The department holds six NBA accreditations, JNTUA research centre recognition, and partnerships with National Instruments and Texas Instruments.","vision":"Transform individuals into globally competent electrical and electronics engineers to realize technological needs of society and develop the department into an ideal education and research center.","mission":["Impart high quality education and enhance students' skills to meet present needs by introducing concurrent trends in curriculum.","Share and disseminate expertise for use in solving problems faced by Electrical & Electronics Engineers and society.","Mould students into responsible citizens with social, ethical and environmental awareness."],"peos":["Apply fundamental knowledge in EEE in industry, academic, and government sectors.","Contribute as educated, ethical, responsible citizens with proven expertise.","Work as grounded professionals individually or as team leaders.","Act with global, societal, and ecological awareness as engineering professionals."],"pos":["Engineering knowledge application","Problem analysis using first principles","Design/development of solutions","Conduct investigations of complex problems","Modern tool usage","Engineer and society considerations","Environment and sustainability","Ethics application","Individual and team work","Communication effectiveness","Project management and finance","Life-long learning recognition"],"psos":["Specify, architect and analyze power systems that efficiently generate, transmit and distribute electrical power in the context of ICT.","Analyze, design and test the performance of modern electrical machines, drive systems and modern lighting systems.","Specify, design, implement and test analog and embedded systems using state-of-the-art components and software."],"programs":[{"name":"B.Tech (Electrical and Electronics Engineering)","intake":"120"},{"name":"M.Tech (Automation and Robotics)","intake":"12"},{"name":"Full-time Ph.D","intake":"-"}],"boardOfStudies":[{"position":"Chairman / HOD (Internal)","name":"Dr. G. Kishor","affiliation":"GPREC"},{"position":"Internal","name":"Dr. T. Bramhananda Reddy","affiliation":"GPREC"},{"position":"Internal","name":"Dr. Y.V. Siva Reddy","affiliation":"GPREC"},{"position":"Internal","name":"Dr. K. Sri Gowri","affiliation":"GPREC"},{"position":"Internal","name":"Dr. M. Siva Satyanarayana","affiliation":"GPREC"},{"position":"Internal","name":"Dr. M. Harshavardhan Reddy","affiliation":"GPREC"},{"position":"Internal","name":"Dr. V. Anantha Lakshmi","affiliation":"GPREC"},{"position":"External (JNTUA)","name":"Dr. M. Vijaya Kumar","affiliation":"Professor & Rector, JNTUA"},{"position":"External (Academic)","name":"Dr. Pradeep Kumar Yemula","affiliation":"IIT Hyderabad"},{"position":"External (Academic)","name":"Dr. J.N. Chandrasekhar","affiliation":"SVEC Tirupati"},{"position":"Industry","name":"Mr. Kalamalla Vijaya Bhaskar Reddy","affiliation":"APSPDCL"},{"position":"Alumnus","name":"Mr. Syed Abdul Akher Jeelan Arafath","affiliation":"HCL Technologies"}],"studentActivities":["Seminars and activities under IEEE PELS/PES/IAS student branch chapters.","Technical workshops on power electronics, IoT, Arduino, and automation.","Industrial visits to power projects and substations.","Activities under the EELS (Ebullient Electrical League of Students) association.","Women in Engineering (WIE) awareness and development programs.","Personality development and career guidance sessions.","Alumni interaction meetings and quiz/poster competitions.","GATE and placement preparation programs.","Participation in the IEI (Institution of Engineers India) student chapter."],"facilities":["Electrical Machines Laboratory","Power Electronics Laboratory","Drives & Control Laboratory","Control Systems & Automation Laboratory","LabVIEW Academy","Power Systems Laboratory","Microcontrollers & IoT Laboratory","e-Yantra Robotics Laboratory","Electrical Circuits Laboratory","Electrical Measurements Laboratory","Electrical Technology Laboratory","Hybrid Power System Laboratory","Research Laboratory"],"departmentAchievements":[{"event":"AICTE IDEA LAB Grant (Rs. 90 Lakhs) awarded to Dr. T. Bramhananda Reddy & A. Pradeep Kumar Yadav","dates":"Apr 2025"},{"event":"EHV Substation Workshop","dates":"Jul - Aug 2025"},{"event":"Arduino Programming Workshop","dates":"Sep 2025"},{"event":"Workshop on Circuits to Intelligence: AI & ML Applications","dates":"Dec 2025"},{"event":"ANOKHA 7.0 Technical Congress","dates":"Feb 2026"}],"gallery":[{"url":"https://www.gprec.ac.in/wp-content/uploads/2019/07/1b-3.jpg","caption":"Department Activity"},{"url":"https://www.gprec.ac.in/wp-content/uploads/2019/07/2.ps_.jpg","caption":"Power Systems Laboratory"},{"url":"https://www.gprec.ac.in/wp-content/uploads/2019/07/2b-3.jpg","caption":"Department Activity"},{"url":"https://www.gprec.ac.in/wp-content/uploads/2019/07/3.pel_.jpg","caption":"Power Electronics Laboratory"},{"url":"https://www.gprec.ac.in/wp-content/uploads/2019/07/3b-3.jpg","caption":"Department Activity"},{"url":"https://www.gprec.ac.in/wp-content/uploads/2019/07/4.LabView.jpg","caption":"LabVIEW Academy"},{"url":"https://www.gprec.ac.in/wp-content/uploads/2019/07/4b-3.jpg","caption":"Department Activity"},{"url":"https://www.gprec.ac.in/wp-content/uploads/2019/07/5.CSAL_.jpg","caption":"Control Systems & Automation Laboratory"},{"url":"https://www.gprec.ac.in/wp-content/uploads/2019/07/5b-2.jpg","caption":"Department Activity"},{"url":"https://www.gprec.ac.in/wp-content/uploads/2019/07/6b-2.jpg","caption":"Department Activity"},{"url":"https://www.gprec.ac.in/wp-content/uploads/2019/07/7.DClab_.jpg","caption":"Drives & Control Laboratory"},{"url":"https://www.gprec.ac.in/wp-content/uploads/2019/07/7b-2.jpg","caption":"Department Activity"},{"url":"https://www.gprec.ac.in/wp-content/uploads/2019/07/8.EM_.jpg","caption":"Electrical Machines Laboratory"},{"url":"https://www.gprec.ac.in/wp-content/uploads/2019/07/9.Microcontrollers.jpg","caption":"Microcontrollers & IoT Laboratory"},{"url":"https://www.gprec.ac.in/wp-content/uploads/2019/07/10.E_yantra.jpg","caption":"e-Yantra Robotics Laboratory"},{"url":"https://www.gprec.ac.in/wp-content/uploads/2019/07/11.et_.jpg","caption":"Electrical Technology Laboratory"},{"url":"https://www.gprec.ac.in/wp-content/uploads/2019/07/CSAL.jpg","caption":"Control Systems & Automation Laboratory"},{"url":"https://www.gprec.ac.in/wp-content/uploads/2019/07/DClab.jpg","caption":"Drives & Control Laboratory"},{"url":"https://www.gprec.ac.in/wp-content/uploads/2019/07/E_yantra.jpg","caption":"e-Yantra Robotics Laboratory"},{"url":"https://www.gprec.ac.in/wp-content/uploads/2019/07/ECL.jpg","caption":"Electrical Circuits Laboratory"},{"url":"https://www.gprec.ac.in/wp-content/uploads/2019/07/EM.jpg","caption":"Electrical Machines Laboratory"},{"url":"https://www.gprec.ac.in/wp-content/uploads/2019/07/EML.jpg","caption":"Electrical Measurements Laboratory"},{"url":"https://www.gprec.ac.in/wp-content/uploads/2019/07/et.jpg","caption":"Electrical Technology Laboratory"},{"url":"https://www.gprec.ac.in/wp-content/uploads/2019/07/LabView.jpg","caption":"LabVIEW Academy"},{"url":"https://www.gprec.ac.in/wp-content/uploads/2019/07/Microcontrollers.jpg","caption":"Microcontrollers & IoT Laboratory"},{"url":"https://www.gprec.ac.in/wp-content/uploads/2019/07/pel.jpg","caption":"Power Electronics Laboratory"},{"url":"https://www.gprec.ac.in/wp-content/uploads/2019/07/ps.jpg","caption":"Power Systems Laboratory"}]},{"id":3,"code":"MEC","name":"Mechanical Engineering (MEC)","about":"Part of the college since its inception in 1985, the department offers a B.Tech (120 intake) and an M.Tech in Advanced Manufacturing Technology (12 intake). Twelve specialized laboratories cover thermal engineering, CAD/CAE/CAM, materials science, machine tools, and heat transfer, using licensed software including ANSYS, CATIA, and MATLAB. The department holds NBA accreditation, JNTUA research centre recognition, and recorded around 80 placement offers in 2020-2021, with 26 faculty members including 16 Ph.D. holders."},{"id":4,"code":"ECE","name":"Electronics and Communication Engineering (ECE)","about":"Established in 1984-85 with 40 students, the department now offers 180 undergraduate seats plus a 12-seat M.Tech in VLSI and Embedded Systems. Laboratories cover microprocessors, digital systems, communications, VLSI design, and IoT applications, supported by centres of excellence with Maven Silicon and Cisco Networking Academy. The department has earned NBA accreditation four times and JNTUA research centre recognition, with multiple SCI journal publications and patents filed by faculty during 2020-2025."},{"id":5,"code":"CSE","name":"Computer Science and Engineering (CSE)","about":"Established in 1991 with an initial intake of 30 students, the department has grown to 300 undergraduates, alongside an M.Tech (12 intake) and a JNTUA-recognized Ph.D. research centre. Laboratories include programming labs, database systems, CISCO networking facilities, and cloud computing resources (IBM BlueMix). The department holds NBA accreditation (renewed 2019), operates as a CISCO Network Academy and IBM training partner, and has placed students at companies including Amazon, Flipkart, TCS, and Infosys."},{"id":6,"code":"CST","name":"Computer Science and Technology (CST)","about":"Established in 2020-21 with an intake of 60 students, the B.Tech programme is supported by Programming, Database, and CISCO-equipped Networking labs, plus an R&D lab with server clusters for cloud and big data research. The department is recognized as a CISCO Network Academy, is accredited by IE(I), and has placed students at TCS, Infosys, and Amazon, including one student securing an Amazon internship at Rs.1,10,000 per month."},{"id":7,"code":"CSB","name":"Computer Science and Business Systems (CSB)","about":"Launched in 2020-21 in partnership with Tata Consultancy Services with an intake of 60 students, the programme blends core computer science with humanities, management sciences, and emerging areas including machine learning, cloud computing, and IoT. Eight well-equipped laboratories support the curriculum, and the department maintains active industry partnerships with Wipro, Infosys, and EPAM for practical training and placements."},{"id":8,"code":"CSM","name":"CSE – Artificial Intelligence & Machine Learning (CSM)","about":"Established in 2021 with an initial intake of 60 students (since expanded to 300), the B.Tech (CSE - AI & ML) programme, including an honors variant, covers foundational computing alongside specialized AI/ML coursework. Seven laboratories support programming, machine learning, deep learning, and NLP work. Students engage through IEEE Computational Intelligence Society and Computer Society of India chapters, with industry partnerships including Wipro, Infosys, and EPAM."},{"id":9,"code":"CSD","name":"CSE- Data Science (CSD)","about":"Established in 2021 with an initial intake of 60 students (since expanded to 120), the B.Tech (CSD) programme is supported by eight laboratories with current-generation systems for programming, machine learning, and data mining. The department maintains industry partnerships with Wipro and Infosys, and hosts IEEE and CSI student chapters alongside a strong focus on the fast-growing data science field."},{"id":10,"code":"HBS","name":"Humanities and Basic Sciences","about":"Established in 1985, this department serves as GPREC's foundational pillar, helping students transition from secondary education into engineering studies. It comprises 43 teaching faculty across Mathematics, Physics, Chemistry, English, and Management, including 19 Ph.D. holders, supported by Physics and Chemistry labs (60 students each), a 36-computer Communicative English Lab, and a 72-system Computer Programming Lab. In 2024-25, 1,169 students completed MOOC certifications through the department."}]$json$::jsonb),
  ('admissionsContent', $json${"btechCategoryA":"70% of the seats are called Category-A seats or Convener seats. These are filled by the Convener, AP EAPCET Admissions through web counseling, strictly on the basis of the rank obtained by the candidate in AP EAPCET and as per the rules of reservation in force.","btechCategoryB":"30% of the seats are called Category-B seats or Management Quota seats. These seats are filled by the college management as per the guidelines issued by APSCHE from time to time.","lateralEntry":"10% of the seats (over and above the sanctioned intake), as supernumerary seats, are allotted to Diploma holders for lateral entry admission into II Year B.Tech. These are filled by the Convener, ECET Admissions strictly on the basis of the rank obtained by the candidate in ECET. There are no management quota seats for lateral entry admissions.","mtechCategoryA":"70% of the seats are called A-Category seats or Convener Quota seats. The Convener conducts admissions through web counseling based on the rank obtained by the candidate in GATE/PGECET, subject to course-wise eligibility rules prescribed by JNTUA, Anantapur.","mtechCategoryB":"30% of the seats are called B-Category seats or Management Quota seats. These are filled by the college management as per the guidelines issued by APSCHE from time to time, subject to ratification."}$json$::jsonb),
  ('feeStructureContent', $json${"btech":"Tuition fee for the academic year 2026-27 is subject to revision by the Government of Andhra Pradesh.","other":"Tuition fee for B.Tech lateral entry and M.Tech programmes for the academic year 2026-27 is subject to revision by the Government of Andhra Pradesh."}$json$::jsonb),
  ('scholarshipsContent', $json${"btech":"Students admitted to B.Tech (Four Year) programmes with an AP EAPCET rank below 2000 receive a complete tuition fee waiver for all four years; those ranking between 2000 and 3000 receive a 50% tuition fee waiver for all four years. Government of Andhra Pradesh tuition fee reimbursement and scholarships are also available to qualifying students.","lateral":"Eligible students admitted to B.Tech (Diploma Holder / Lateral Entry) programmes can avail Government of Andhra Pradesh tuition fee reimbursement and scholarships.","mtech":"M.Tech students admitted through GATE are eligible for an AICTE stipend. Government of Andhra Pradesh tuition fee reimbursement is available for eligible students admitted through PGECET, subject to eligibility requirements."}$json$::jsonb),
  ('aboutRdContent', $json${"committee":"A nine-member committee led by the Dean, R&D (Dr. T. Brahmananda Reddy, Professor, EEE), with coordinators for R&D, Project Assessment & Evaluation, and Consultancy drawn from across departments.","objectives":"Promote research awareness, encourage multidisciplinary collaboration, build funding-agency and industry partnerships, support community engagement, improve publication quality, protect IPR, and enable international exchange programs.","incentives":"Faculty receive a cash incentive of 2.5% of the sanctioned external grant amount (paid after project completion from management funds, split equally among co-investigators). Students winning competitions receive one-way travel fare, and fabrication/hardware projects are eligible for funding.","inHouseScheme":"Teams of up to 3 members (including the Principal Investigator), maximum duration of two years, with periodic progress monitoring. Completion requires at least one full-length publication in an SCI/SCIE/Scopus/ESCI-indexed journal, or a filed patent as an alternative."}$json$::jsonb),
  ('fundingCampaigns', $json$[{"id":"fund-scholarship","title":"Scholarship Fund","description":"Supports tuition assistance for meritorious students from low-income families.","goal":500000},{"id":"fund-infra","title":"Campus Infrastructure Fund","description":"Upgrades to labs, classrooms, and campus facilities.","goal":800000},{"id":"fund-sports","title":"Sports & Cultural Fund","description":"Equipment and event support for student sports and cultural activities.","goal":200000}]$json$::jsonb),
  ('alumniEvents', $json$[{"id":"event-seed-1","title":"Annual Alumni Meet 2026","date":"2026-12-20","location":"GPREC Campus, Kurnool","description":"Reconnect with batchmates and faculty at the annual on-campus alumni gathering.","createdBy":"gprec"},{"id":"event-seed-2","title":"Career Webinar: Breaking into Tech","date":"2026-08-15","location":"Online","description":"A panel of alumni working at top tech companies share career advice for recent graduates.","createdBy":"gprec"}]$json$::jsonb),
  ('careerListings', $json$[{"id":1,"title":"Professor of Practice","description":"GPREC is inviting applications for the position of Professor of Practice. Refer to the official notification and guidelines documents below for eligibility criteria, application procedure, and last date to apply.","notificationUrl":"https://www.gprec.ac.in/collegepdf/GPREC-Professor-of-Practice-Notification-2026.pdf","guidelinesUrl":"https://www.gprec.ac.in/collegepdf/Guidelines-for-Professor-of-Practice-GPREC-April-2026.pdf"}]$json$::jsonb),
  ('studentVoices', $json$[{"id":"voice-1","quote":"I proudly completed my Mechanical Engineering at GPREC, where I gained technical knowledge, values, ethics, and the strength to face challenges.","name":"Ms. Venkata Saranya","role":"Alumnus, Mechanical","photoDataUrl":"https://www.gprec.ac.in/wp-content/uploads/2025/09/Ms.-Venkata-Saranya-92x92.png"},{"id":"voice-2","quote":"Joining GPREC as a lateral entry student was a turning point in my journey. The supportive faculty and peers made me feel at home.","name":"Thahid Shaik Tappa","role":"Alumnus, Mechanical","photoDataUrl":"https://www.gprec.ac.in/wp-content/uploads/2025/09/Thahid-Shaik-Tappa-92x92.png"},{"id":"voice-3","quote":"GPREC has given me unforgettable memories and invaluable lessons. It was more than academics; it was about personal growth.","name":"J Prem","role":"Alumnus, CSE","photoDataUrl":"https://www.gprec.ac.in/wp-content/uploads/2025/09/J-PREM-92x92.png"},{"id":"voice-4","quote":"Sports, event management, hands-on projects, and faculty support helped me become confident, adaptable, and industry-ready.","name":"K. Rohith Reddy","role":"Alumnus, Civil","photoDataUrl":"https://www.gprec.ac.in/wp-content/uploads/2025/09/IMG_20250429_162151821_AE-removebg-preview-2-92x92.png"},{"id":"voice-5","quote":"GPREC gave me academic strength, leadership opportunities, placement support, and the confidence to grow professionally.","name":"Swetha Saron","role":"Alumnus, Civil","photoDataUrl":"https://www.gprec.ac.in/wp-content/uploads/2025/09/SwethaSaron-92x92.png"},{"id":"voice-6","quote":"The curriculum, clubs, sports, and fests helped me grow in many dimensions and build lasting college memories.","name":"Supraja","role":"Alumnus, Mechanical","photoDataUrl":"https://www.gprec.ac.in/wp-content/uploads/2019/06/Supraja-Reddy-92x92.jpg"},{"id":"voice-7","quote":"GPREC helped me discover a better version of myself through academics, placement training, clubs, and forums.","name":"T. Roshni","role":"Alumnus, Civil","photoDataUrl":"https://www.gprec.ac.in/wp-content/uploads/2019/06/Screenshot_20190528-182608-92x92.png"},{"id":"voice-8","quote":"The college identifies talents, builds strengths, and turns students into problem solvers and real engineers.","name":"Nisitha Chennuru","role":"Student, ECE","photoDataUrl":"https://www.gprec.ac.in/wp-content/uploads/2019/06/nisi-photo-92x92.jpg"},{"id":"voice-9","quote":"GPREC provides a strong learning environment, helpful professors, platforms for growth, and good placement opportunities.","name":"Ragasree G","role":"Alumni, 2018 Batch","photoDataUrl":"https://www.gprec.ac.in/wp-content/uploads/2019/05/Ragasree-Pic-92x92.jpg"},{"id":"voice-10","quote":"Infrastructure, library, gym, indoor stadium, and faculty support helped me learn values and contribute to society.","name":"V. Rakesh Reddy","role":"Alumni, 2019 Batch","photoDataUrl":"https://www.gprec.ac.in/wp-content/uploads/2018/03/IMG_20190215_194622-92x92.jpg"}]$json$::jsonb),
