-- Data retention standards. These rows classify tables by behavior; cleanup jobs can read this
-- metadata to decide whether a table is permanent, archived after a cycle, or purged later.
INSERT INTO data_retention_policies (
  policy_code, behavior, description, retention_months, retention_basis, disposal_action, legal_hold_allowed
) VALUES
  ('PERMANENT_ACADEMIC', 'Academic evidence', 'Official academic, identity, curriculum, result, and schedule records that support certificates, marks, and statutory reporting.', NULL, 'created_at', 'Keep permanently or archive read-only according to statutory/university requirements.', true),
  ('ACTIVE_CYCLE_PLUS_1_SEM', 'Student-facing operational data', 'Current operational records visible to students during an active academic/exam cycle.', 12, 'created_at', 'Archive after the cycle and one additional semester once grievance windows close.', true),
  ('TEMP_90_DAYS', 'Temporary working data', 'Drafts, previews, short-lived requests, and working copies used to complete an operation.', 3, 'created_at', 'Delete after reconciliation, backup, and operational sign-off.', false),
  ('AUDIT_7_YEARS', 'Audit and change history', 'Administrative activity, release actions, edits, access events, and decision trails.', 84, 'created_at', 'Keep immutable; export before archival migration.', true),
  ('SECURITY_3_YEARS', 'Security and authentication', 'Credential metadata, password rotation state, failed-login counters, and authentication recovery references.', 36, 'updated_at', 'Purge disabled accounts after review; never expose password hashes in exports.', true),
  ('FINANCE_8_YEARS', 'Financial transaction evidence', 'Payments, fee dues, contributions, and financial reconciliation records.', 96, 'created_at', 'Archive read-only after statutory accounting retention.', true),
  ('USER_CONTENT_5_YEARS', 'User-generated content', 'Student/alumni submissions, memories, documents, and uploaded content not used as permanent academic evidence.', 60, 'created_at', 'Archive or delete after owner/legal review.', true),
  ('REFERENCE_ACTIVE', 'Reference/configuration data', 'Departments, faculty directory, content settings, catalog rows, and lookup/config tables.', NULL, 'updated_at', 'Retain while active; archive superseded versions when replaced.', true)
ON CONFLICT (policy_code) DO UPDATE SET
  behavior = EXCLUDED.behavior,
  description = EXCLUDED.description,
  retention_months = EXCLUDED.retention_months,
  retention_basis = EXCLUDED.retention_basis,
  disposal_action = EXCLUDED.disposal_action,
  legal_hold_allowed = EXCLUDED.legal_hold_allowed,
  updated_at = now();

